          "_sourceYear": 2025,
          "_sourceExamType": "mid",
          "_qKey": "original/high/h1/1mid/25_매산고_1학기_중간_고1_기출.js_1",
          "_assessmentSkill": "계산 안정성",
          "_assessmentQualityScore": 100,
